phi1 = 31.23*pi/180; lam1 = 121.47*pi/180;
phi2 = 33.73*pi/180; lam2 = -118.27*pi/180;
dphi = phi2 - phi1;
dlam = lam2 - lam1;
a = sin(dphi/2)^2 + cos(phi1)*cos(phi2)*sin(dlam/2)^2;
R_nm = 3440.065;
d_gc = 2 * R_nm * asin(sqrt(a));
fprintf('Great-circle distance: %.1f nautical miles\n', d_gc);

service = [10 20 40 20 15];
barh(1, service(1), 'FaceColor', [0.25 0.55 0.9]);
xlabel('Time'); ylabel('QC'); title('Quay crane schedule sketch');

t = 0:0.1:60;
n = 0.08; w0 = 0.8; w = sqrt(w0^2 - n^2);
theta = exp(-n*t).*cos(w*t);
plot(t, theta, 'LineWidth', 2);

x = -2:0.01:2;
y1 = x.^2; y2 = 4*ones(size(x));
fill([x fliplr(x)], [y1 fliplr(y2)], 'b', 'FaceAlpha', 0.3);

mu = 1200; sigma = 80;
x = mu-4*sigma:1:mu+4*sigma;
y = normpdf(x, mu, sigma);
plot(x, y, 'LineWidth', 2);

W = [0 3 2 inf 5; 3 0 inf 4 inf; 2 inf 0 inf 2; inf 4 inf 0 1; 5 inf 2 1 0];
G = graph(W);
plot(G);
